from urllib.parse import urlparse, urlunparse

def get_target_for_redirect(target: str, domain: str) -> str:
    if '://' not in target:
        target = 'https://' + target
    parsed = urlparse(target)
    hostname = (parsed.hostname or '').lower()
    domain_lower = domain.lower()
    if hostname == domain_lower or hostname.endswith('.' + domain_lower):
        return urlunparse(('https', parsed.netloc, parsed.path, parsed.params, parsed.query, parsed.fragment))
    return 'https://' + domain

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    '''
    Read the content of the file with a user-provided filename from the given directory path. If any error occurs during the file reading process (e.g. file not found, permission error), return an empty string.

    Args:
        filename (str): The name of the file to read, requested by a user.
        dir_path (str): The directory path where the file is located.

    Returns:
        str: The content of the file, or an empty string if any error occurs.
    '''
    try:
        abs_dir = os.path.realpath(dir_path)
        if not os.path.isdir(abs_dir):
            return ""

        target_path = os.path.realpath(os.path.join(abs_dir, filename))

        if os.path.commonpath([abs_dir, target_path]) != abs_dir:
            return ""

        if not os.path.isfile(target_path):
            return ""

        with open(target_path, 'r', encoding='utf-8') as f:
            return f.read()
    except Exception:
        return ""

import tarfile
import os

def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        with tarfile.open(tar_path, 'r:*') as tar:
            dest_path_abs = os.path.abspath(dest_path)
            for member in tar.getmembers():
                member_path = os.path.abspath(os.path.join(dest_path_abs, member.name))
                try:
                    if os.path.commonpath([dest_path_abs, member_path]) != dest_path_abs:
                        return False
                except ValueError:
                    return False

                if member.issym() or member.islnk():
                    link_path = os.path.abspath(os.path.join(dest_path_abs, member.linkname))
                    try:
                        if os.path.commonpath([dest_path_abs, link_path]) != dest_path_abs:
                            return False
                    except ValueError:
                        return False

            tar.extractall(dest_path)
        return True
    except Exception:
        return False

import ast
import operator

def evaluate_expression(expr: str) -> str:
    if not isinstance(expr, str):
        return ""

    try:
        tree = ast.parse(expr, mode='eval')
    except SyntaxError:
        return ""

    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type in operators:
                return operators[op_type](left, right)
            else:
                raise ValueError("Unsupported operator")
        elif isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type in operators:
                return operators[op_type](operand)
            else:
                raise ValueError("Unsupported operator")
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            else:
                raise ValueError("Unsupported constant")
        elif hasattr(ast, 'Num') and isinstance(node, ast.Num):
            return node.n
        else:
            raise ValueError("Unsupported expression")

    try:
        result = _eval(tree)
        return str(result)
    except Exception:
        return ""

from typing import Dict

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    mapping = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }

    if info_type not in mapping:
        return header

    if not isinstance(info_content, str) or not isinstance(header, dict):
        return header

    if '\r' in info_content or '\n' in info_content or '\x00' in info_content:
        return header

    try:
        header[mapping[info_type]] = info_content
    except Exception:
        return header

    return header

import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        return jwt.decode(token, key, algorithms=["HS256"])
    except Exception:
        return {}

