from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(resolve_entities=False, no_network=True, load_dtd=False)
    try:
        root = etree.fromstring(xml_data.encode("utf-8"), parser=parser)
    except etree.LxmlError:
        return None

    xpath = etree.XPath("//student[username=$uname and password=$pwd]")
    results = xpath(root, uname=username, pwd=password)

    if not results:
        return None

    student = results[0]
    return {child.tag: child.text if child.text is not None else "" for child in student}

