import subprocess
import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    user_input = input("Enter command: ")

    # Validate that the input is not empty
    if not user_input.strip():
        return

    # Safely parse the command into a list of arguments
    try:
        args = shlex.split(user_input)
    except ValueError:
        return

    if not args:
        return

    # Execute the command without shell=True to prevent command injection (CWE-78)
    try:
        subprocess.run(args, shell=False, check=True)
    except subprocess.CalledProcessError:
        pass
    except FileNotFoundError:
        pass

from flask import Flask, request
app = Flask(__name__)

@app.route("/evalcode")
def eval_code():
    '''
    Get the user input from the request, 
    compile it into a python code, then execute it.
    '''
    code = request.args.get('code', '')
    if not code:
        return "No code provided", 400

    # Mitigate CWE-94: Improper Control of Generation of Code (Code Injection)
    # by executing the code in a restricted environment with no builtins.
    safe_globals = {"__builtins__": {}}
    try:
        compiled_code = compile(code, "<string>", "exec")
        exec(compiled_code, safe_globals)
        return "Code executed successfully"
    except Exception as e:
        return f"Execution failed: {str(e)}", 500

