import ast

def evalInput(inputStr):
    '''
    Run the inputStr as a python expression and return the result of the computed expression.
    '''
    tree = ast.parse(inputStr, mode='eval')

    for node in ast.walk(tree):
        if isinstance(node, ast.Attribute):
            raise ValueError("Attribute access is not allowed for security reasons")

    safe_builtins = {
        'abs': abs, 'min': min, 'max': max, 'sum': sum, 'len': len,
        'range': range, 'int': int, 'float': float, 'str': str,
        'bool': bool, 'list': list, 'dict': dict, 'set': set,
        'tuple': tuple, 'round': round, 'pow': pow, 'divmod': divmod,
        'enumerate': enumerate, 'zip': zip, 'map': map, 'filter': filter,
        'sorted': sorted, 'reversed': reversed, 'all': all, 'any': any,
        'print': print, 'True': True, 'False': False, 'None': None
    }

    return eval(compile(tree, '<string>', 'eval'), {"__builtins__": safe_builtins}, {})

