import io
import pickle
import builtins

class SafeUnpickler(pickle.Unpickler):
    def find_class(self, module, name):
        # Only allow a safe subset of builtins to prevent arbitrary code execution
        if module == 'builtins' and name in (
            'range', 'list', 'dict', 'set', 'tuple', 'int', 'float', 'str', 
            'bool', 'bytes', 'complex', 'frozenset', 'bytearray', 'memoryview'
        ):
            return getattr(builtins, name)
        raise pickle.UnpicklingError(f"global '{module}.{name}' is forbidden")

def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if isinstance(pickled, str):
        pickled = pickled.encode('latin-1')
    return SafeUnpickler(io.BytesIO(pickled)).load()

